import React from 'react';

const First = () => {


        
    return (
        <>
            <style>{`
                .intro { color: #2563eb; margin-bottom: 8px; text-align: center; }
                .summary { font-size: 18px; line-height: 1.5; text-align: center; }
            `}</style>
            <div class="intro">
                <h1>Welcome to my website!</h1>
            </div>
            <p class="summary">
                You can find my thoughts here.
            <br></br>
            <b>And <i>pictures</i></b> of scientists!
            </p>
        </>
  );
}

export default First;
